<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>Maze Game with 24 Bots</title>
  <style>
    * {
      box-sizing: border-box;
      margin: 0;
      padding: 0;
    }

    body {
      font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
      background-color: #1a1a2e;
      color: #eee;
      display: flex;
      flex-direction: column;
      align-items: center;
      min-height: 100vh;
      padding: 20px;
    }

    h1 {
      margin-bottom: 15px;
      font-size: 2rem;
      text-align: center;
      color: #4cc9f0;
    }

    .hud {
      display: flex;
      gap: 30px;
      margin-bottom: 20px;
      background-color: rgba(255, 255, 255, 0.1);
      padding: 15px 25px;
      border-radius: 8px;
    }

    .hud-item {
      display: flex;
      flex-direction: column;
      align-items: center;
    }

    .hud-label {
      font-size: 0.9rem;
      color: #aaa;
      margin-bottom: 5px;
    }

    .hud-value {
      font-size: 1.4rem;
      font-weight: bold;
      color: #f72585;
    }

    #maze-container {
      position: relative;
      box-shadow: 0 0 20px rgba(0, 0, 0, 0.3);
      border-radius: 8px;
      overflow: hidden;
    }

    canvas#maze {
      display: block;
      background-color: #16213e;
    }

    button#reset {
      margin-top: 25px;
      padding: 12px 30px;
