      background-color: #f72585;
      color: white;
      border: none;
      border-radius: 6px;
      cursor: pointer;
      transition: all 0.2s ease;
    }

    button#reset:hover {
      background-color: #b5179e;
      transform: translateY(-2px);
    }

    button#reset:active {
      transform: translateY(0);
    }
  </style>
</head>
<body>
  <h1>Maze Game with 24 Bots</h1>

  <div class="hud">
    <div class="hud-item">
      <span class="hud-label">Completed</span>
      <span id="completed" class="hud-value">0</span>
    </div>
    <div class="hud-item">
      <span class="hud-label">Time (seconds)</span>
      <span id="timer" class="hud-value">0.0</span>
    </div>
  </div>

  <div id="maze-container">
    <canvas id="maze"></canvas>
  </div>

  <button id="reset">Reset Game</button>

  <script>
    // Maze dimensions
    const MAZE_WIDTH = 15;
    const MAZE_HEIGHT = 15;

    // Canvas settings
    const CELL_SIZE = 30; // pixels per cell
    const CANVAS_WIDTH = MAZE_WIDTH * CELL_SIZE + 20;
    const CANVAS_HEIGHT = MAZE_HEIGHT * CELL_SIZE + 20;

    // Game state
    let mazeGrid = [];
    let bots = [];
    let completedCount = 0;
    let startTime = 0;
    let animationId = null;
    let isRunning = false;

    // DOM elements
    const canvas = document.getElementById('maze');
    const ctx = canvas.getContext('2d');
    const completedEl = document.getElementById('completed');
    const timerEl = document.getElementById('timer');
    const resetBtn = document.getElementById('reset');

    // Initialize canvas size explicitly
    canvas.width = CANVAS_WIDTH;
    canvas.height = CANVAS_HEIGHT;

    // Maze generation using recursive backtracker
    function generateMaze() {
      // Initialize grid with all walls (1)
      mazeGrid = [];
      for (let y = 0; y < MAZE_HEIGHT; y++) {
        const row = [];
        for (let x = 0; x < MAZE_WIDTH; x++) {
          row.push({ 
            x, y,
            walls: { top: true, right: true, bottom: true, left: true },
            visited: false
          });
        }
        mazeGrid.push(row);
      }

      // Recursive backtracker algorithm
      const stack = [];
      const startCell = mazeGrid[0][0];
      startCell.visited = true;
      stack.push(startCell);

      while (stack.length > 0) {
        const current = stack[stack.length - 1];
        const neighbors = [];

        // Check all four directions
        if (current.y > 0 && !mazeGrid[current.y - 1][current.x].visited) {
          neighbors.push({ direction: 'top', cell: mazeGrid[current.y - 1][current.x] });
        }
        if (current.x < MAZE_WIDTH - 1 && !mazeGrid[current.y][current.x + 1].visited) {
          neighbors.push({ direction: 'right', cell: mazeGrid[current.y][current.x + 1] });
        }
        if (current.y < MAZE_HEIGHT - 1 && !mazeGrid[current.y + 1][current.x].visited) {
          neighbors.push({ direction: 'bottom', cell: mazeGrid[current.y + 1][current.x] });
        }
        if (current.x > 0 && !mazeGrid[current.y][current.x - 1].visited) {
          neighbors.push({ direction: 'left', cell: mazeGrid[current.y][current.x - 1] });
        }

        if (neighbors.length > 0) {
          const randomNeighbor = neighbors[Math.floor(Math.random() * neighbors.length)];

          // Remove walls between current and neighbor
          switch (randomNeighbor.direction) {
            case 'top':
              current.walls.top = false;
              randomNeighbor.cell.walls.bottom = false;
              break;
            case 'right':
              current.walls.right = false;
              randomNeighbor.cell.walls.left = false;
              break;
            case 'bottom':
              current.walls.bottom = false;
              randomNeighbor.cell.walls.top = false;
              break;
            case 'left':
              current.walls.left = false;
              randomNeighbor.cell.walls.right = false;
              break;
          }

          randomNeighbor.cell.visited = true;
          stack.push(randomNeighbor.cell);
        } else {
          stack.pop();
        }
      }

      // Reset visited flags
      for (let y = 0; y < MAZE_HEIGHT; y++) {
        for (let x = 0; x < MAZE_WIDTH; x++) {
          mazeGrid[y][x].visited = false;
        }
      }
    }

    // BFS pathfinding to find shortest path from start to exit
    function bfsPath(startX, startY, endX, endY) {
      const queue = [{ x: startX, y: startY, path: [] }];
      const visited = new Set();
      visited.add(`${startX},${startY}`);

      while (queue.length > 0) {
        const { x, y, path } = queue.shift();

        if (x === endX && y === endY) {
          return [...path, { x, y }];
        }

        const cell = mazeGrid[y][x];

        // Check all possible moves based on walls
        const directions = [
          { dx: 0, dy: -1, wall: 'top' },
          { dx: 1, dy: 0, wall: 'right' },
          { dx: 0, dy: 1, wall: 'bottom' },
          { dx: -1, dy: 0, wall: 'left' }
        ];

        for (const dir of directions) {
          if (!cell.walls[dir.wall]) {
            const nx = x + dir.dx;
            const ny = y + dir.dy;

            if (nx >= 0 && nx < MAZE_WIDTH && ny >= 0 && ny < MAZE_HEIGHT && !visited.has(`${nx},${ny}`)) {
              visited.add(`${nx},${ny}`);
              queue.push({ 
                x: nx, 
                y: ny, 
                path: [...path, { x, y }] 
              });
            }
          }
        }
      }

      return []; // No path found
    }

    // Create bots with staggered start times and paths to exit
    function createBots() {
      const startX = 0;
      const startY = 0;
      const endX = MAZE_WIDTH - 1;
      const endY = MAZE_HEIGHT - 1;

      // Get path from BFS for reference (we'll use it for all bots)
      const shortestPath = bfsPath(startX, startY, endX, endY);

      bots = [];
      for (let i = 0; i < 24; i++) {
        // Stagger start times slightly
        const staggerDelay = Math.floor(Math.random() * 5); // 0-4 steps delay

        // Create bot object with state
        bots.push({
          id: i,
          x: startX,
          y: startY,
          pathIndex: 0,
          path: shortestPath, // All bots use the same shortest path for simplicity and reliability
          staggerDelay: staggerDelay,
          completed: false,
          completionTime: null,
          color: `hsl(${Math.random() * 360}, 70%, 60%)`
        });
      }
    }

    // Draw maze and bots
    function drawMaze() {
      ctx.fillStyle = '#16213e';
      ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

      const offset = 10; // Center the maze in canvas

      // Draw walls
      ctx.strokeStyle = '#4cc9f0';
      ctx.lineWidth = 2;
      ctx.beginPath();

      for (let y = 0; y < MAZE_HEIGHT; y++) {
        for (let x = 0; x < MAZE_WIDTH; x++) {
          const cell = mazeGrid[y][x];
          const cx = offset + x * CELL_SIZE;
          const cy = offset + y * CELL_SIZE;

          if (cell.walls.top) {
            ctx.moveTo(cx, cy);
            ctx.lineTo(cx + CELL_SIZE, cy);
          }
          if (cell.walls.right) {
            ctx.moveTo(cx + CELL_SIZE, cy);
            ctx.lineTo(cx + CELL_SIZE, cy + CELL_SIZE);
          }
          if (cell.walls.bottom) {
            ctx.moveTo(cx, cy + CELL_SIZE);
            ctx.lineTo(cx + CELL_SIZE, cy + CELL_SIZE);
          }
          if (cell.walls.left) {
            ctx.moveTo(cx, cy);
            ctx.lineTo(cx, cy + CELL_SIZE);
          }
        }
      }

      // Draw exit
      const exitX = offset + (MAZE_WIDTH - 1) * CELL_SIZE;
      const exitY = offset + (MAZE_HEIGHT - 1) * CELL_SIZE;
      ctx.fillStyle = '#4361ee';
      ctx.fillRect(exitX, exitY, CELL_SIZE, CELL_SIZE);

      // Draw bots
      for (const bot of bots) {
        if (!bot.completed) {
          const bx = offset + bot.x * CELL_SIZE + CELL_SIZE / 2;
          const by = offset + bot.y * CELL_SIZE + CELL_SIZE / 2;

          ctx.fillStyle = bot.color;
          ctx.beginPath();
          ctx.arc(bx, by, CELL_SIZE / 3, 0, Math.PI * 2);
          ctx.fill();

          // Add a small glow effect
          ctx.shadowColor = bot.color;
          ctx.shadowBlur = 5;
          ctx.stroke();
          ctx.shadowBlur = 0; // Reset shadow for other elements
        }
      }

      // Draw completed bots at the exit
      const completedBots = bots.filter(b => b.completed);
      let i = 0;
      for (const bot of completedBots) {
        const bx = offset + (MAZE_WIDTH - 1) * CELL_SIZE + CELL_SIZE / 2 + (i % 3 - 1) * 5;
        const by = offset + (MAZE_HEIGHT - 1) * CELL_SIZE + CELL_SIZE / 2 + Math.floor(i / 3) * 5;

        ctx.fillStyle = bot.color;
        ctx.beginPath();
        ctx.arc(bx, by, 4, 0, Math.PI * 2);
        ctx.fill();

        i++;
      }
    }

    // Update game state
    function updateGame() {
      if (!isRunning) return;

      const now = Date.now();
      const elapsedMs = now - startTime;

      timerEl.textContent = (elapsedMs / 1000).toFixed(1);

      let allCompleted = true;
      for (const bot of bots) {
        if (!bot.completed) {
          allCompleted = false;

          // Apply stagger delay
          if (bot.staggerDelay > 0) {
            bot.staggerDelay--;
          } else {
            // Move bot along path
            if (bot.pathIndex < bot.path.length - 1) {
              const nextStep = bot.path[bot.pathIndex + 1];

              // Simple movement: move one step per tick
              bot.x = nextStep.x;
              bot.y = nextStep.y;
              bot.pathIndex++;
            }

            // Check if reached exit
            if (bot.x === MAZE_WIDTH - 1 && bot.y === MAZE_HEIGHT - 1) {
              bot.completed = true;
              bot.completionTime = elapsedMs;
              completedCount++;
              completedEl.textContent = completedCount;
            }
          }
        }
      }

      drawMaze();

      // Check if all bots have completed
      if (allCompleted && isRunning) {
        isRunning = false;
      } else if (!isRunning && completedCount < 24) {
        // Restart animation loop if needed
        requestAnimationFrame(updateGame);
      }
    }

    // Game tick function for deterministic simulation
    window.game = {
      get bots() {
        return bots;
      },

      get completed() {
        let count = 0;
        for (const bot of bots) {
          if (bot.completed) count++;
        }
        return count;
      },

      get elapsedMs() {
        if (!startTime) return 0;
        return Date.now() - startTime;
      },

      tick(n) {
        // Run n steps deterministically
        for (let step = 0; step < n; step++) {
          let allCompleted = true;

          for (const bot of bots) {
            if (!bot.completed) {
              allCompleted = false;

              // Apply stagger delay
              if (bot.staggerDelay > 0) {
                bot.staggerDelay--;
              } else {
                // Move bot along path
                if (bot.pathIndex < bot.path.length - 1) {
                  const nextStep = bot.path[bot.pathIndex + 1];

                  // Simple movement: move one step per tick
                  bot.x = nextStep.x;
                  bot.y = nextStep.y;
                  bot.pathIndex++;
                }

                // Check if reached exit
                if (bot.x === MAZE_WIDTH - 1 && bot.y === MAZE_HEIGHT - 1) {
                  bot.completed = true;
                }
              }
            }
          }

          if (allCompleted) break; // All bots finished, no need to continue
        }

        // Update UI after simulation
        completedCount = this.completed;
        completedEl.textContent = completedCount;

        // Draw final state
        drawMaze();
      },

      reset() {
        // Stop any running animation
        isRunning = false;

        // Reset game state
        generateMaze();
        createBots();
        startTime = Date.now();
        completedCount = 0;
        completedEl.textContent = '0';

        // Draw initial state
        drawMaze();

        // Start animation loop
        isRunning = true;
        requestAnimationFrame(updateGame);
      }
    };

    // Initialize game on load
    resetBtn.addEventListener('click', () => {
      window.game.reset();
    });

    // Initial setup
    generateMaze();
    createBots();
    startTime = Date.now();
    drawMaze();

    // Start animation loop
    isRunning = true;
    requestAnimationFrame(updateGame);
  </script>
</body>
</html>
